"use client";
import { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { Loader2, PlusCircle, MessageCircle, Heart, Trash2, Edit3, Save, X } from 'lucide-react';

export default function CommunityPage() {
  const { user, token } = useContext(AuthContext);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // סטייטים ליצירת פוסט חדש
  const [showForm, setShowForm] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newContent, setNewContent] = useState("");
  const [newTags, setNewTags] = useState("");

  // סטייטים לעריכת פוסט (לאדמינים)
  const [editingPostId, setEditingPostId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [editContent, setEditContent] = useState("");

  useEffect(() => {
    const fetchCommunityPosts = async () => {
      try {
        const res = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/community-posts`);
        setPosts(res.data);
      } catch (error) {
        console.error("שגיאה במשיכת פוסטים של הקהילה:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchCommunityPosts();
  }, []);

  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!newTitle.trim() || !newContent.trim()) return alert("חובה למלא כותרת ותוכן!");
    const tagsArray = newTags.split(',').map(tag => tag.trim()).filter(tag => tag !== "");

    try {
      const res = await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/community-posts`, 
        { title: newTitle, content: newContent, tags: tagsArray },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      const createdPost = {
        ...res.data.post,
        author: { username: user.username, avatarUrl: user.avatarUrl }
      };

      setPosts([createdPost, ...posts]);
      setNewTitle(""); setNewContent(""); setNewTags(""); setShowForm(false);
    } catch (error) {
      console.error("שגיאה ביצירת פוסט:", error);
    }
  };

  const handleLike = async (postId) => {
    if (!user) return alert("יש להתחבר כדי לעשות לייק!");
    try {
      await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/community-posts/${postId}/like`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      setPosts(posts.map(post => {
        if (post._id === postId) {
          const hasLiked = post.likes?.includes(user.id);
          let updatedLikes = [...(post.likes || [])];
          if (hasLiked) updatedLikes = updatedLikes.filter(id => id !== user.id);
          else updatedLikes.push(user.id);
          return { ...post, likes: updatedLikes };
        }
        return post;
      }));
    } catch (error) {
      console.error("שגיאה בלייק:", error);
    }
  };

  // --- פונקציות ניהול לאדמין ---

  const handleDeletePost = async (postId) => {
    if (!window.confirm("פעולת מנהל: האם אתה בטוח שברצונך למחוק פוסט זה לצמיתות?")) return;
    try {
      await axios.delete(`${process.env.NEXT_PUBLIC_API_URL}/community-posts/${postId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPosts(posts.filter(post => post._id !== postId));
    } catch (error) {
      console.error("שגיאה במחיקה:", error);
      alert("שגיאה במחיקת הפוסט.");
    }
  };

  const startEditing = (post) => {
    setEditingPostId(post._id);
    setEditTitle(post.title);
    setEditContent(post.content);
  };

  const cancelEditing = () => {
    setEditingPostId(null);
    setEditTitle("");
    setEditContent("");
  };

  const handleUpdatePost = async (postId) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/community-posts/${postId}`, 
        { title: editTitle, content: editContent },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      setPosts(posts.map(post => 
        post._id === postId ? { ...post, title: editTitle, content: editContent } : post
      ));
      setEditingPostId(null);
    } catch (error) {
      console.error("שגיאה בעדכון הפוסט:", error);
      alert("שגיאה בעדכון הפוסט.");
    }
  };

  if (loading) return <div className="min-h-screen flex justify-center items-center"><Loader2 className="w-12 h-12 animate-spin text-indigo-500" /></div>;

  return (
    <main className="min-h-screen bg-slate-50 py-12 px-4 md:px-8">
      <div className="max-w-4xl mx-auto">
        
        <div className="flex justify-between items-center mb-10">
          <div>
            <h1 className="text-4xl font-black text-slate-900 mb-2">קהילת <span className="text-indigo-600">האנימה</span></h1>
            <p className="text-slate-600">המקום שלכם לדבר, לשתף ולחפור על הסדרות האהובות עליכם.</p>
          </div>
          
          {user && (
            <button 
              onClick={() => setShowForm(!showForm)}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-3 rounded-xl flex items-center gap-2 transition shadow-sm font-medium"
            >
              <PlusCircle className="w-5 h-5" />
              {showForm ? 'ביטול' : 'פוסט חדש'}
            </button>
          )}
        </div>

        {showForm && (
          <form onSubmit={handleCreatePost} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-10 animation-fade-in">
            {/* ... (טופס היצירה נשאר אותו דבר) ... */}
            <h2 className="text-xl font-bold mb-4 text-slate-800">מה בא לך לשתף?</h2>
            <input type="text" placeholder="כותרת הפוסט..." className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-4 focus:ring-2 focus:ring-indigo-500 outline-none transition" value={newTitle} onChange={(e) => setNewTitle(e.target.value)} />
            <textarea placeholder="תוכן הפוסט..." rows="4" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-4 focus:ring-2 focus:ring-indigo-500 outline-none transition resize-none" value={newContent} onChange={(e) => setNewContent(e.target.value)}></textarea>
            <input type="text" placeholder="תגיות (מופרדות בפסיקים)" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-6 focus:ring-2 focus:ring-indigo-500 outline-none transition text-sm" value={newTags} onChange={(e) => setNewTags(e.target.value)} />
            <button type="submit" className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-3 rounded-xl transition">פרסם פוסט</button>
          </form>
        )}

        <div className="flex flex-col gap-6">
          {posts.length === 0 ? (
            <div className="text-center py-20 text-slate-500 bg-white rounded-2xl border border-slate-100">
              <MessageCircle className="w-12 h-12 mx-auto mb-4 text-slate-300" />
              <p className="text-lg">הקהילה עדיין שקטה... היה הראשון לכתוב פוסט!</p>
            </div>
          ) : (
            posts.map(post => (
              <div key={post._id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative group">
                
                {/* הצגת כפתורי ניהול רק אם המשתמש הוא אדמין */}
                {user?.role === 'admin' && editingPostId !== post._id && (
                  <div className="absolute top-4 left-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => startEditing(post)} className="bg-slate-100 hover:bg-indigo-100 text-indigo-600 p-2 rounded-lg transition" title="ערוך פוסט (אדמין)">
                      <Edit3 className="w-4 h-4" />
                    </button>
                    <button onClick={() => handleDeletePost(post._id)} className="bg-slate-100 hover:bg-rose-100 text-rose-600 p-2 rounded-lg transition" title="מחק פוסט (אדמין)">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                )}

                {editingPostId === post._id ? (
                  /* מצב עריכה (אדמין) */
                  <div className="flex flex-col gap-4">
                    <div className="text-rose-500 text-sm font-bold mb-2">עריכת מנהל מופעלת</div>
                    <input type="text" value={editTitle} onChange={(e) => setEditTitle(e.target.value)} className="text-xl font-bold bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
                    <textarea value={editContent} onChange={(e) => setEditContent(e.target.value)} rows="4" className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none resize-none" />
                    <div className="flex gap-3 justify-end mt-2">
                      <button onClick={cancelEditing} className="flex items-center gap-1 text-slate-500 hover:text-slate-700 px-4 py-2 font-medium"><X className="w-4 h-4" /> ביטול</button>
                      <button onClick={() => handleUpdatePost(post._id)} className="flex items-center gap-1 bg-emerald-500 hover:bg-emerald-600 text-white px-5 py-2 rounded-xl font-medium transition"><Save className="w-4 h-4" /> שמור שינויים</button>
                    </div>
                  </div>
                ) : (
                  /* תצוגה רגילה */
                  <>
                    <div className="flex items-center gap-3 mb-4">
                      <img src={post.author?.avatarUrl || 'https://via.placeholder.com/40'} alt="avatar" className="w-10 h-10 rounded-full border border-slate-200" />
                      <div>
                        <div className="font-bold text-slate-800">{post.author?.username || 'משתמש לא ידוע'}</div>
                        <div className="text-xs text-slate-500">{new Date(post.createdAt).toLocaleDateString('he-IL')}</div>
                      </div>
                    </div>
                    
                    <h2 className="text-2xl font-bold text-slate-900 mb-2">{post.title}</h2>
                    <p className="text-slate-700 whitespace-pre-wrap mb-4 leading-relaxed">{post.content}</p>
                    
                    {post.tags && post.tags.length > 0 && (
                      <div className="flex flex-wrap gap-2 mb-6">
                        {post.tags.map((tag, idx) => (
                          <span key={idx} className="bg-slate-100 text-slate-600 text-xs px-2.5 py-1 rounded-md font-medium">#{tag}</span>
                        ))}
                      </div>
                    )}
                    
                    <div className="border-t border-slate-100 pt-4 mt-2">
                      <button onClick={() => handleLike(post._id)} className="flex items-center gap-1.5 text-slate-500 hover:text-rose-500 transition font-medium">
                        <Heart className={`w-5 h-5 ${post.likes?.includes(user?.id) ? 'fill-rose-500 text-rose-500' : ''}`} />
                        <span>{post.likes?.length || 0}</span>
                      </button>
                    </div>
                  </>
                )}
              </div>
            ))
          )}
        </div>

      </div>
    </main>
  );
}